window.__STATIC_BLOB__ = '';
window.__DATA_READY = (async function(){
  try {
    var b64 = window.__STATIC_BLOB__;
    var bin = Uint8Array.from(atob(b64), function(c){ return c.charCodeAt(0); });
    var stream = new Blob([bin]).stream().pipeThrough(new DecompressionStream('gzip'));
    var text = await new Response(stream).text();
    window.__STATIC_DATA__ = JSON.parse(text);
  } catch (e) {
    console.error('Static example: failed to decompress data.js', e);
    window.__STATIC_DATA__ = {};
  }
  window.__STATIC_BLOB__ = null;
  return window.__STATIC_DATA__;
})();
